import React, { useState } from 'react'
import Head from 'next/head'
import Link from 'next/link'
import fetch from 'isomorphic-unfetch'

const Home = ({ data }) => {
  // const week = Object.values(data[`week-1`])
  const week = {
    "monday": {
      "label":"Mon",
      "exercise":"Rest",
      "tag":"rest"
    },
    "tuesday": {
      "label":"Tue",
      "exercise":"3 mi run",
      "tag":"run"
    },
    "wednesday": {
      "label":"Wed",
      "exercise":"2 mi run or cross",
      "tag":"crossrun"
    },
    "thursday": {
      "label":"Thu",
      "exercise":"3 mi run",
      "tag":"run"
    },
    "friday": {
      "label":"Fri",
      "exercise":"Rest",
      "tag":"rest"
    },
    "saturday": {
      "label":"Sat",
      "exercise":"30 min cross",
      "tag":"cross"
    },
    "sunday": {
      "label":"Sun",
      "exercise":"4 mi run",
      "tag":"run"
    }
  }

  return(
    <div className="container">

      <Head>
        <title>Week 1</title>
        <link rel="icon" href="" />
      </Head>

      <div className="week-header">
        <h1>Week 1</h1>
      </div>


      <div className="exercise-grid">
      {
       Object.values(week).map((foo, i) => (
         <div key={i} className="details-container">

          {
            foo.tag === 'rest' ? 
              <div className="dot-tag rest"></div> : 
            foo.tag === 'run' ? 
              <div className="run"></div> :
            foo.tag === 'cross' ? 
              <div className="cross"></div> :
            foo.tag === 'crossrun' ? 
              <div className="crossrun"></div> :
              <div className="other"></div>
          }

            <div className="day-exercise">
              <h1>{foo.label}</h1>
              <p>{foo.exercise}</p>
            </div>
          </div>
        ))
      }
      </div>

      <style jsx>{`
        body{
          margin: 0;
          padding: 0;
        }

        .container{
          height: 100vh;
          width: 100%;
          display: flex;
          flex-flow: column;
          justify-content: center;
          align-items: center;
          font-family: sans-serif;
        }

        .week-header{
          font-size: 4rem;
          margin: 0;
          padding: 0;
          display: grid;
          grid-template-columns: 1fr 1fr;
          height: 100%;
        }

        .week-header h1{
          place-self: center end;
        }

        .exercise-grid{
          display: grid;
          grid-template-rows: repeat(5, 14.25%);
          width: 50%;
        }

        .details-container{
          display: grid;
          grid-template-columns: 50% 50%;
        }

        .dot-tag{
          align-self: center;
          justify-self: end;
        }

        .day-exercise{
          margin-left: 5rem;
        }


        .rest{
          height: 10px;
          width: 10px;
          background-color: cyan;
          border-radius: 100px;
        }
        .run{
          height: 10px;
          width: 10px;
          background-color: red;
          border-radius: 100px;
        }
        .cross{
          height: 10px;
          width: 10px;
          background-color: yellow;
          border-radius: 100px;
        }
        .crossrun{
          height: 10px;
          width: 10px;
          background-color: orange;
          border-radius: 100px;
        }
        .other{
          height: 10px;
          width: 10px;
          background-color: black;
          border-radius: 100px;
        }

      `}
      </style>

    </div>
  )
}

// Home.getInitialProps = async () => {
//   const res = await fetch('http://localhost:3000/api/daily')
//   const json = await res.json()

//   return { data: json }
// }

export default Home
